"import os\nimport json\n\nbrains_dir = r\"C:\\Users\\John Jacob\\.gemini\\antigravity\\brain\"\nconversations = [\n    \"43501d54-94a1-43ac-8dd7-7b9742dce801\",\n    \"cf3c8394-0a7b-4e70-acf5-b3bbbb227053\",\n    \"b8be5ad8-2723-4f7f-a057-27cef6eac548\"\n]\n\nfor conv in conversations:\n    log_path = os.path.join(brains_dir, conv, \".system_generated\", \"logs\", \"transcript.jsonl\")\n    if not os.path.exists(log_path):\n        continue\n    \n    print(f\"\\nChecking {conv}...\")\n    with open(log_path, 'r', encoding='utf-8') as f:\n        for idx, line in enumerate(f):\n            if \"BemiBiosEntryPoint\" in line or \"BemiBiosCore.c\" in line:\n                try:\n                    step = json.loads(line)\n                except Exception:\n                    print(f\"  Line {idx}: JSON load error\")\n                    continue\n                \n                sidx = step.get(\"step_index\")\n                stype = step.get(\"type\")\n                # Look for tool name or arguments\n                tool_info = \"\"\n                if \"tool_calls\" in step:\n                    tcs = []\n                    for tc in step[\"tool_calls\"]:\n                        tcs.append(tc.get(\"name\"))\n                    tool_info = f\" | tool_calls: {tcs}\"\n                \n                print(f\"  Step {sidx or idx} | Type: {stype}{tool_info} | Length: {len(line)}\")\n"